import React from 'react';
import { Button, Modal } from '@linm-soft/common-components';
import { UnsavedChangesModal } from '../../../../../components/form';
import {
  VoucherSearchSlideout,
  ProcessingLevelApproveModal,
  VoucherPrintModal,
} from '../../../../../components/voucher';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

export const TamUngFormModals: React.FC<{ vm: TamUngFormViewModel }> = ({ vm }) => {
  const {
    cfg,
    labels,
    isNew,
    voucherCode,
    processingLevel,
    processingOpts,
    styles: df,
    tid,
    showSearchSlideout,
    setShowSearchSlideout,
    fetchSearchList,
    handleOpenFromSearch,
    showApproveModal,
    setShowApproveModal,
    handleApproveConfirm,
    approving,
    showPrintModal,
    setShowPrintModal,
    handlePrintConfirm,
    printing,
    showUnsavedModal,
    cancelLeave,
    confirmLeave,
    showDeleteModal,
    setShowDeleteModal,
    handleDelete,
    deleting,
  } = vm;

  return (
    <>
      <VoucherSearchSlideout
        isOpen={showSearchSlideout}
        onClose={() => setShowSearchSlideout(false)}
        title="Tìm phiếu tạm ứng"
        testIdPrefix={cfg.testIdPrefix}
        listScope={cfg.searchListScope}
        fetchList={fetchSearchList}
        onOpenVoucher={(voucherId, resultIds, items) => {
          setShowSearchSlideout(false);
          handleOpenFromSearch(voucherId, resultIds, items);
        }}
        processingLevelFilterOptions={processingOpts}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, processingOpts)}
      />

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={processingLevel}
        levelOptions={processingOpts}
        onConfirm={handleApproveConfirm}
        saving={approving}
        testIdPrefix={cfg.testIdPrefix}
      />

      <VoucherPrintModal
        isOpen={showPrintModal}
        onClose={() => setShowPrintModal(false)}
        voucherTitle={!isNew ? `${labels.title} — ${voucherCode || '...'}` : undefined}
        onPrint={handlePrintConfirm}
        printing={printing}
        testIdPrefix={cfg.testIdPrefix}
      />

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={tid('unsaved-modal')}
      />

      <Modal isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} title={labels.deleteConfirmTitle}>
        <p>{labels.deleteConfirmBody}</p>
        <div className={df.modalActions}>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>Hủy</Button>
          <Button variant="danger" onClick={handleDelete} loading={deleting}>Xóa</Button>
        </div>
      </Modal>
    </>
  );
};
