import React, { useRef } from 'react';
import { FormMode } from '../../../../../components/form';
import { VoucherFormToolbar, VoucherFormStatusGroup } from '../../../../../components/voucher';
import { useTopbarAutoHideOnScroll, useVoucherFormShellHeight } from '../../../../../components/form';
import { isStandalone } from '../../../../../dev/isStandalone';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import { useTamUngFormController } from '../hooks/useTamUngFormController';
import { TamUngValidationBanner } from './TamUngValidationBanner';
import { TamUngHeaderSection } from './TamUngHeaderSection';
import { TamUngLinesSection } from './TamUngLinesSection';
import { TamUngFooterSection } from './TamUngFooterSection';
import { TamUngFormModals } from './TamUngFormModals';

export const TamUngFormParent: React.FC = () => {
  const vm = useTamUngFormController();
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  useVoucherFormShellHeight(shellRef);
  useTopbarAutoHideOnScroll(scrollRef, !isStandalone);

  if (vm.showInitialLoading) {
    return (
      <div className={vm.styles.loading} data-testid={vm.tid('loading')}>
        Đang tải...
      </div>
    );
  }

  const {
    cfg,
    labels,
    styles: df,
    isNew,
    voucherCode,
    status,
    processingLevel,
    processingOpts,
    toolbarMode,
    isViewMode,
    isStatusLocked,
    saving,
    saveLabel,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    handleBack,
    setShowApproveModal,
    handleCopy,
    setShowPrintModal,
    setShowSearchSlideout,
    handleNew,
    setFormMode,
    handleSave,
    handleCancel,
    setShowDeleteModal,
    tid,
    validationErrors,
    bannerClosed,
    bannerExpanded,
    setBannerExpanded,
    setBannerClosed,
    validationBannerId,
    toolbarDisabledReasons,
    copySourceVoucherCode,
    formPermissions,
  } = vm;

  const canActOnDraft = !isNew && status === 'Draft' && !isStatusLocked;
  const canApprove = canActOnDraft && (formPermissions?.canApprove ?? formPermissions?.canUnpost ?? true);

  return (
    <div
      ref={shellRef}
      className={df.pageVoucher}
      data-voucher-form-shell
      data-testid={tid('form')}
    >
      <div className={df.pageFormHeader}>
        <div className={df.stickyTop}>
          <VoucherFormToolbar
            testIdPrefix={cfg.testIdPrefix}
            title={isNew ? labels.createTitle : `${labels.title} — ${voucherCode || '...'}`}
            processingLevelBadge={
              !isNew ? (
                <VoucherFormStatusGroup
                  processingLevelLabel={formatProcessingLevelFromOptions(processingLevel, processingOpts)}
                />
              ) : undefined
            }
            formMode={toolbarMode}
            showViewHint={isViewMode && !isStatusLocked}
            copySourceVoucherCode={copySourceVoucherCode}
            showApproveButton={!isNew && (formPermissions?.canApprove ?? false)}
            canApprove={canApprove}
            showPostButton={false}
            canPost={false}
            canCopy={!isNew}
            canPrint={!isNew}
            canEdit={!isNew && !isStatusLocked}
            canDelete={canActOnDraft}
            disabledReasons={toolbarDisabledReasons}
            saving={saving}
            saveLabel={saveLabel}
            searchNav={hasSearchNav ? {
              index: searchNavIndex,
              total: searchResultIds.length,
              onFirst: () => navigateToSearchId(searchResultIds[0]),
              onPrev: () => navigateToSearchId(searchResultIds[searchNavIndex - 1]),
              onNext: () => navigateToSearchId(searchResultIds[searchNavIndex + 1]),
              onEnd: () => navigateToSearchId(searchResultIds[searchResultIds.length - 1]),
            } : undefined}
            onBack={handleBack}
            onApprove={() => setShowApproveModal(true)}
            onPost={() => {}}
            onCopy={handleCopy}
            onPrint={() => setShowPrintModal(true)}
            onSearch={() => setShowSearchSlideout(true)}
            onNew={handleNew}
            onEdit={() => setFormMode(FormMode.Edit)}
            onSave={() => { void handleSave(); }}
            onCancel={handleCancel}
            onDelete={() => setShowDeleteModal(true)}
            insetShell
          />
          {isStatusLocked && (
            <div className={df.readOnlyHint} style={{ margin: '0 16px 12px' }}>
              <i className="fas fa-lock" /> Chỉ xem — đã ghi sổ, mức xử lý cuối, hoặc đã tất toán
            </div>
          )}
        </div>
      </div>

      <div ref={scrollRef} className={df.pageFormScroll} data-testid={tid('form-scroll')}>
        <TamUngValidationBanner
          validationErrors={validationErrors}
          bannerClosed={bannerClosed}
          bannerExpanded={bannerExpanded}
          setBannerExpanded={setBannerExpanded}
          setBannerClosed={setBannerClosed}
          validationBannerId={validationBannerId}
          tid={tid}
          styles={df}
        />

        <TamUngHeaderSection vm={vm} />
        <TamUngLinesSection vm={vm} />
      </div>

      <div className={df.pageFormFooter} data-testid={tid('form-footer')}>
        <TamUngFooterSection vm={vm} />
      </div>

      <TamUngFormModals vm={vm} />
    </div>
  );
};

export default TamUngFormParent;
